// lib/ai/trafficMastersSquad.ts
// Squad "Traffic Masters": 16 personas de IA especialistas em tráfego pago,
// extraídas programaticamente de um prompt-pack (13-traffic-masters.md) para
// evitar erro de transcrição manual num arquivo de 2000+ linhas. Cada persona
// mantém o prompt de sistema original (em inglês); a instrução de responder em
// português é adicionada pela API route (app/api/clients/[id]/squad/route.ts),
// não aqui, pra manter o prompt de cada persona fiel ao original.

export type SquadGroup = 'chief' | 'platform' | 'functional'

export interface SquadMember {
  id: string
  name: string
  emoji: string
  group: SquadGroup
  shortDescription: string
  systemPrompt: string
}

